package repository

import (
	"github.com/samber/lo"
)

type Error struct {
	Type      string  `json:"type"`
	Reason    string  `json:"reason"`
	Index     *string `json:"index"`
	Shard     string  `json:"shard"`
	IndexUuid string  `json:"index_uuid"`
	CausedBy  any     `json:"caused_by,omitempty"`
	RootCause []struct {
		Type   string `json:"type"`
		Reason string `json:"reason"`
	} `json:"root_cause"`
}

type Retry struct {
	Bulk   int `json:"bulk,omitempty"`
	Search int `json:"search,omitempty"`
}

// Failure holds details for an individual failure.
type Failure struct {
	Index string `json:"index"`
	Id    string `json:"id"`
	Cause struct {
		Type      string `json:"type"`
		Reason    string `json:"reason"`
		Index     string `json:"index"`
		Shard     string `json:"shard"`
		IndexUuid string `json:"index_uuid"`
	} `json:"cause"`
	Status int `json:"status"`
}

type Shards struct {
	Total      int `json:"total"`
	Successful int `json:"successful"`
	Failed     int `json:"failed"`
}

type BulkResponseItem struct {
	Index  *AnyResponse `json:"index,omitempty"`
	Create *AnyResponse `json:"create,omitempty"`
	Update *AnyResponse `json:"update,omitempty"`
	Delete *AnyResponse `json:"delete,omitempty"`
}

type BulkResponse struct {
	Errors     *bool               `json:"errors,omitempty"`
	Error      *Error              `json:"error,omitempty"`
	Items      []*BulkResponseItem `json:"items"`
	ErrorItems []*Error            `json:"-"`
	Took       int                 `json:"took"`
}

// GetResponseInfo returns the information regarding the result of the individual
// operation in a bulk request.
func (responseItem BulkResponseItem) GetResponseInfo() *AnyResponse {
	response, _ := lo.Coalesce(responseItem.Index, responseItem.Create, responseItem.Update, responseItem.Delete)

	return response
}

// GetOperationResult returns the result of the operation. Successful values are created,
// updated, and deleted.
func (responseItem BulkResponseItem) GetOperationResult() *string {
	response := responseItem.GetResponseInfo()

	if response == nil || response.Error != nil {
		return nil
	}

	return response.Result
}

// GetError returns the reason for the bulk item error.
func (responseItem BulkResponseItem) GetError() *Error {
	response := responseItem.GetResponseInfo()

	if response == nil || response.Error == nil {
		return nil
	}

	return response.Error
}
