// AnyResponse contain all response properties.
type AnyResponse struct {
	Result               *string             `json:"result,omitempty"`
	Errors               *bool               `json:"errors,omitempty"`
	Error                *Error              `json:"error,omitempty"`
	Index                *string             `json:"_index,omitempty"`
	Id                   string              `json:"_id,omitempty"`
	Shards               *Shards             `json:"_shards,omitempty"`
	Version              *int                `json:"_version,omitempty"`
	Status               int                 `json:"status,omitempty"`
	SeqNo                *int                `json:"_seq_no,omitempty"`
	PrimaryTerm          *int                `json:"_primary_term,omitempty"`
	Took                 int                 `json:"took,omitempty"`                   // The number of milliseconds from start to end of the whole operation.
	TimedOut             bool                `json:"timed_out,omitempty"`              // This flag is set to true if any of the requests executed during the update by Query execution has timed out.
	Total                int                 `json:"total,omitempty"`                  // The number of documents that were successfully processed.
	Updated              int                 `json:"updated,omitempty"`                // The number of documents that were successfully updated.
	Deleted              int                 `json:"deleted,omitempty"`                // The number of documents that were successfully deleted.
	Batches              int                 `json:"batches,omitempty"`                // The number of scroll responses pulled back by the update by Query.
	VersionConflicts     int                 `json:"version_conflicts,omitempty"`      // The number of version conflicts that the update by Query hit.
	NoOps                int                 `json:"noops,omitempty"`                  // The number of documents that were ignored because the Script used for the update by Query returned a noop value for ctx.op.
	Retries              *Retry              `json:"retries,omitempty"`                // The number of retries attempted by update by Query. bulk is the number of bulk actions retried, and search is the number of search actions retried.
	ThrottledMillis      int                 `json:"throttled_millis,omitempty"`       // Number of milliseconds the request slept to conform to requests_per_second.
	ThrottledUntilMillis int                 `json:"throttled_until_millis,omitempty"` // This field should always be equal to zero in an _update_by_query response. It only has meaning when using the Task API, where it indicates the next time (in milliseconds since epoch) a throttled request will be executed again in order to conform to requests_per_second.
	Failures             []*Failure          `json:"failures,omitempty"`               // Array of failures if there were any unrecoverable errors during the process. If this is non-empty then the request aborted because of those failures. Update by Query is implemented using batches. Any failure causes the entire process to abort, but all failures in the current batch are collected into the array. You can use the conflicts option to prevent reindex from aborting on version conflicts.
	Items                []*BulkResponseItem `json:"items,omitempty"`                  // Bulk response items.
	Docs                 []*AnyResponse      `json:"docs,omitempty"`                   // Multi get response documents.
	Responses            []*AnyResponse      `json:"responses,omitempty"`              // Multi search responses.
}

func (r *AnyResponse) IsError() bool {
	return r != nil && r.Error != nil
}

func (r *AnyResponse) IsDocumentMissingException() bool {
	const documentMissingException = "document_missing_exception"

	return r.IsError() &&
		r.Status == http.StatusNotFound &&
		r.Error.Type == documentMissingException
}

func (r *AnyResponse) IsBulkItemSuccess() bool {
	// Bulk item responses are considered successful if they have no errors or if they fail
	// to update a non existing document.
	return !r.IsError() || r.IsDocumentMissingException()
}
