	const (
		bulkItemRequestErrorMessage = "opensearch_emitter.countResponseStatusAndLogError: bulk request item failed"
		documentDetailsKey          = "document_detail"
	)

	response := bulkResponseItem.GetResponseInfo()

	if response == nil {
		return false, false
	}

	var indexName string
	if response.Index != nil {
		indexName = *response.Index
	}

	var (
		tags = []metrics.Tag{
			metrics.NewTag(telemetry.PayloadSchemaNameTag, request.PayloadSchemaName),
			metrics.NewTag(telemetry.OperationIdTag, request.Action),
			metrics.NewTag(telemetry.IndexNameTag, indexName),
		}
		hasShardFailures = response.Shards != nil && response.Shards.Failed > 0
	)

	if response.IsBulkItemSuccess() {
		// do not count or log document missing exceptions
		if !response.IsDocumentMissingException() {
			telemetry.Increment(
				request.LogContext,
				group.Emitter,
				metric.BulkRequestSuccessCount,
				tags...,
			)
		}

		return false, hasShardFailures
	}

	tags = append(
		tags,
		metrics.NewTag(telemetry.ErrorTypeTag, response.Error.Type),
	)

	telemetry.Increment(
		request.LogContext,
		group.Emitter,
		metric.BulkRequestFailureCount,
		tags...,
	)

	log.Errorw(
		request.LogContext,
		bulkItemRequestErrorMessage,
		log.OperationKey,
		request.BulkItems[0].Op,
		documentDetailsKey,
		response,
		// document contains the err
	)

	return true, hasShardFailures
}

