type BulkOperationItem[ParamArgType AllParamConstraint] struct {
	BulkIndexHeader      *bulkIndexHeader             `json:"-"` // The "header" for the index request.
	BulkUpdateHeader     *bulkUpdateHeader            `json:"-"` // The "header" for the update request.
	BulkDeleteHeader     *bulkDeleteHeader            `json:"-"` // The "header" for the delete request.
	BulkIndexDocBody     map[string]any               `json:"-"` // The properties for the index request.
	BulkUpdateDocBody    *UpdateRequest[ParamArgType] `json:"-"` // The properties for the update request.
	BulkUpdateScriptBody *bulkScript[ParamArgType]    `json:"-"` // The Script body for the update request.

	TenantUuid          string       `json:"-"` // The unique identifier of the tenant of the event. // TODO: This needs to be a collection associated to bulk items present.
	PublicSchemaVersion string       `json:"-"` // The UEM public schema version of the event.
	PayloadSchemaName   string       `json:"-"` // The name of the UEM public event which resulted in this change.
	LogContext          *log.Context `json:"-"` // The correlation identifier for this bulk item.

	// Determines whether to mark records dirty when record is out of sync. Eg:
	// UPDATE operation CREATEs a document instead of updating would mean
	// records are probably out of sync.
	DetectDrift bool   `json:"-"`
	Op          string `json:"-"`

	EventMetadata any `json:"metadata,omitempty"` // Additional information from the corresponding event for logging purpose.
}

// QueryDetailsItem contains general properties of a Query.
type QueryDetailsItem[BodyType any] struct {
	LogContext                        *log.Context  `json:"-"`                     // The log context of the message. // TODO: This needs to be a collection associated to bulk items present.
	TenantUuid                        string        `json:"tenant_uuid"`           // The unique identifier of the tenant of the event. // TODO: This needs to be a collection associated to bulk items present.
	PublicSchemaVersion               string        `json:"public_schema_version"` // The UEM public schema version of the event.
	PayloadSchemaName                 string        `json:"payload_schema_name"`   // The name of the UEM public event which resulted in this change.
	ExecuteSequenceOnMatchButNoUpdate bool          `json:"-"`
	Action                            string        `json:"action"`      // The bulk request action. // TODO: Remove; this is not used any longer.
	Indices                           []string      `json:"indices"`     // The index or table to scope this operation.
	DocumentID                        string        `json:"document_id"` // ID of the record in the NoSQL database. // TODO: This needs to be an dictionary.
	RoutingID                         []string      `json:"routing_id"`  // ID of the record in the NoSQL database. // TODO: This needs to be an dictionary.
	Body                              BodyType      `json:"-"`           // The reader providing the request body.
