	PitID                             []string      `json:"-"`           // The Pit identifiers.
}

// BulkQueryDetailsItem contains general properties of a Query.
type BulkQueryDetailsItem[BodyType any, DocArgType AllParamConstraint] struct {
	*QueryDetailsItem[BodyType]
	BulkItems []*BulkOperationItem[DocArgType] `json:"-"` // The bulk upsert/delete items.
}

func (qd *QueryDetailsItem[BodyType]) Equal(queryDetailsItem *QueryDetailsItem[BodyType]) (bool, error) {
	const directComparisonFormat = "%s: %v != %v"
	var multiError *multierror.Error

	if qd == queryDetailsItem {
		return true, nil
	}

	if qd.TenantUuid != queryDetailsItem.TenantUuid {
		const tenantUuidProperty = "TenantUuid"
		multiError = multierror.Append(
			multiError,
			errors.Newf(directComparisonFormat, tenantUuidProperty, qd.TenantUuid, queryDetailsItem.TenantUuid),
		)
	}

	if qd.PublicSchemaVersion != queryDetailsItem.PublicSchemaVersion {
		const publicSchemaVersionProperty = "PublicSchemaVersion"
		multiError = multierror.Append(
			multiError,
			errors.Newf(
				directComparisonFormat,
				publicSchemaVersionProperty,
				qd.PublicSchemaVersion,
				queryDetailsItem.PublicSchemaVersion,
			),
		)
	}

	if qd.PayloadSchemaName != queryDetailsItem.PayloadSchemaName {
		const payloadSchemaProperty = "PayloadSchemaName"
		multiError = multierror.Append(
			multiError,
			errors.Newf(
				directComparisonFormat,
				payloadSchemaProperty,
				qd.PayloadSchemaName,
				queryDetailsItem.PayloadSchemaName,
			),
		)
	}

	if qd.ExecuteSequenceOnMatchButNoUpdate != queryDetailsItem.ExecuteSequenceOnMatchButNoUpdate {
		const executeSequenceProperty = "ExecuteSequenceOnMatchButNoUpdate"
		multiError = multierror.Append(
			multiError,
			errors.Newf(
				directComparisonFormat,
				executeSequenceProperty,
				qd.ExecuteSequenceOnMatchButNoUpdate,
				queryDetailsItem.ExecuteSequenceOnMatchButNoUpdate,
			),
		)
	}

	if qd.Action != queryDetailsItem.Action {
		const actionProperty = "Action"
		multiError = multierror.Append(
			multiError,
			errors.Newf(directComparisonFormat, actionProperty, qd.Action, queryDetailsItem.Action),
		)
	}

	if qd.DocumentID != queryDetailsItem.DocumentID {
		const documentIdProperty = "DocumentID"
		multiError = multierror.Append(
			multiError,
			errors.Newf(directComparisonFormat, documentIdProperty, qd.DocumentID, queryDetailsItem.DocumentID),
		)
	}

	if qd.From != queryDetailsItem.From {
		const fromProperty = "From"
		multiError = multierror.Append(
			multiError,
			errors.Newf(directComparisonFormat, fromProperty, qd.From, queryDetailsItem.From),
		)
	}

	if qd.Size != queryDetailsItem.Size {
		const sizeProperty = "Size"
		multiError = multierror.Append(
			multiError,
			errors.Newf(directComparisonFormat, sizeProperty, qd.Size, queryDetailsItem.Size),
		)
	}

	// Deep Compare
	const deepCompareFormat = "%s: %#v"
	if diff := pretty.Diff(qd.Indices, queryDetailsItem.Indices); diff != nil {
		const indicesProperty = "Indices"
		multiError = multierror.Append(
			multiError,
			errors.Newf(deepCompareFormat, indicesProperty, diff),
		)
	}

	if diff := pretty.Diff(qd.RoutingID, queryDetailsItem.RoutingID); diff != nil {
		const routingIdProperty = "RoutingID"
		multiError = multierror.Append(
			multiError,
			errors.Newf(deepCompareFormat, routingIdProperty, diff),
		)
	}

	if diff := pretty.Diff(
		qd.LogContext.Get(log.CorrelationIdKey),
		queryDetailsItem.LogContext.Get(log.CorrelationIdKey),
	); diff != nil {
		const correlationIdProperty = "CorrelationId"

		multiError = multierror.Append(
			multiError,
			errors.Newf(deepCompareFormat, correlationIdProperty, diff),
		)
	}

	return multiError == nil || multiError.Len() == 0, multiError
}

func (qd *QueryDetailsItem[BodyType]) AddRoutingId(routingId string) {
	if len(routingId) > 0 {
		qd.RoutingID = append(qd.RoutingID, routingId)
	}
}
